var COURSE_PL_AR = [{day: 1, title: `Pierwsze powitania`, title_native: `التحيات الأولى`, focus: `Zaczynasz podróż w Ammanie w Jordanii i uczysz się najprostszych powitań. Celem jest przywitać się, pożegnać i odpowiedzieć uprzejmie w hotelu, sklepie lub kawiarni.`, vocab: [{ar: `مرحبا`, pl: `cześć / dzień dobry`, ipa: `mar-ha-ban`},{ar: `أهلا`, pl: `witaj`, ipa: `ah-lan`},{ar: `صباح الخير`, pl: `dzień dobry rano`, ipa: `sa-bah al-chajr`},{ar: `مساء الخير`, pl: `dobry wieczór`, ipa: `ma-sa al-chajr`},{ar: `شكرا`, pl: `dziękuję`, ipa: `szuk-ran`},{ar: `عفوا`, pl: `proszę / nie ma za co`, ipa: `af-wan`},{ar: `نعم`, pl: `tak`, ipa: `na-am`},{ar: `لا`, pl: `nie`, ipa: `la`},{ar: `وداعا`, pl: `do widzenia`, ipa: `wa-da-an`},{ar: `لو سمحت`, pl: `proszę / przepraszam`, ipa: `lau sa-maht`}], phrases: [{ar: `مرحبا، كيف حالك؟`, pl: `Cześć, jak się masz?`, ipa: `mar-ha-ban, kaj-fa ha-luk`},{ar: `أنا بخير، شكرا`, pl: `Mam się dobrze, dziękuję`, ipa: `a-na bi-chajr, szuk-ran`},{ar: `صباح الخير`, pl: `Dzień dobry rano`, ipa: `sa-bah al-chajr`},{ar: `مساء الخير`, pl: `Dobry wieczór`, ipa: `ma-sa al-chajr`},{ar: `إلى اللقاء`, pl: `Do zobaczenia`, ipa: `i-la al-li-ka`},{ar: `شكرا جزيلا`, pl: `Bardzo dziękuję`, ipa: `szuk-ran dża-zi-lan`}], grammar: `W języku arabskim powitania często mają formę uprzejmą i mogą być używane w wielu sytuacjach. مرحبا jest bezpieczne i neutralne, gdy nie wiesz, czy użyć formy bardziej formalnej. Zwróć uwagę, że العربية pisze się od prawej do lewej, ale wymowę możesz ćwiczyć z zapisu IPA.`, practice: [`Przywitaj recepcjonistę w hotelu słowem مرحبا.`,`Powiedz „dziękuję bardzo” po arabsku.`,`Odpowiedz na pytanie كيف حالك؟ zdaniem أنا بخير، شكرا.`,`Przećwicz rozróżnienie صباح الخير i مساء الخير.`,`Napisz krótką wymianę: cześć, jak się masz, dziękuję, do zobaczenia.`]},{day: 2, title: `Przedstawianie się`, title_native: `التعارف`, focus: `Jesteś w hostelu w Dubaju i poznajesz innych podróżnych. Uczysz się mówić, jak masz na imię, skąd jesteś i że jesteś z Polski.`, vocab: [{ar: `أنا`, pl: `ja`, ipa: `a-na`},{ar: `أنت`, pl: `ty`, ipa: `an-ta`},{ar: `اسمي`, pl: `mam na imię`, ipa: `is-mi`},{ar: `اسمك`, pl: `twoje imię`, ipa: `is-muk`},{ar: `من`, pl: `z / od`, ipa: `min`},{ar: `بولندا`, pl: `Polska`, ipa: `bu-lan-da`},{ar: `سائح`, pl: `turysta`, ipa: `sa-ih`},{ar: `صديق`, pl: `przyjaciel`, ipa: `sa-dik`},{ar: `تشرفنا`, pl: `miło mi`, ipa: `ta-szar-raf-na`},{ar: `جواز سفر`, pl: `paszport`, ipa: `dża-waz sa-far`}], phrases: [{ar: `اسمي آدم`, pl: `Mam na imię Adam`, ipa: `is-mi a-dam`},{ar: `ما اسمك؟`, pl: `Jak masz na imię?`, ipa: `ma is-muk`},{ar: `أنا من بولندا`, pl: `Jestem z Polski`, ipa: `a-na min bu-lan-da`},{ar: `أنا سائح`, pl: `Jestem turystą`, ipa: `a-na sa-ih`},{ar: `تشرفنا`, pl: `Miło mi`, ipa: `ta-szar-raf-na`},{ar: `هل أنت من هنا؟`, pl: `Czy jesteś stąd?`, ipa: `hal an-ta min hu-na`}], grammar: `أنا znaczy „ja” i nie odmienia się przez rodzaj w podstawowym użyciu. W wielu prostych zdaniach po arabsku nie używa się czasownika „być” w czasie teraźniejszym: أنا من بولندا dosłownie brzmi „ja z Polski”. To naturalna konstrukcja i warto ją zapamiętać jako gotowy wzór.`, practice: [`Powiedz po arabsku: „Mam na imię...” z własnym imieniem.`,`Zapytaj kogoś, jak ma na imię.`,`Powiedz: „Jestem z Polski”.`,`Połącz powitanie z przedstawieniem się.`,`Wyobraź sobie rozmowę w hostelu i napisz trzy krótkie arabskie zdania.`]},{day: 3, title: `Podstawowe pytania`, title_native: `الأسئلة الأساسية`, focus: `Spacerujesz po Marrakeszu i potrzebujesz zadawać proste pytania. Uczysz się słów pytających: gdzie, co, kiedy, ile i czy.`, vocab: [{ar: `أين`, pl: `gdzie`, ipa: `aj-na`},{ar: `ماذا`, pl: `co`, ipa: `ma-za`},{ar: `متى`, pl: `kiedy`, ipa: `ma-ta`},{ar: `كم`, pl: `ile`, ipa: `kam`},{ar: `هل`, pl: `czy`, ipa: `hal`},{ar: `لماذا`, pl: `dlaczego`, ipa: `li-ma-za`},{ar: `كيف`, pl: `jak`, ipa: `kaj-fa`},{ar: `هذا`, pl: `to / ten`, ipa: `ha-za`},{ar: `هناك`, pl: `tam`, ipa: `hu-nak`},{ar: `هنا`, pl: `tutaj`, ipa: `hu-na`}], phrases: [{ar: `أين الفندق؟`, pl: `Gdzie jest hotel?`, ipa: `aj-na al-fun-duk`},{ar: `ماذا تريد؟`, pl: `Czego chcesz?`, ipa: `ma-za tu-rid`},{ar: `كم السعر؟`, pl: `Ile kosztuje?`, ipa: `kam as-si-r`},{ar: `هل هذا قريب؟`, pl: `Czy to jest blisko?`, ipa: `hal ha-za ka-rib`},{ar: `كيف أذهب إلى هنا؟`, pl: `Jak idę tutaj?`, ipa: `kaj-fa az-hab i-la hu-na`},{ar: `متى يفتح؟`, pl: `Kiedy jest otwarte?`, ipa: `ma-ta jaf-tah`}], grammar: `هل tworzy pytanie typu „czy” i zwykle stoi na początku zdania. Słowa pytające, takie jak أين i كم, także pojawiają się najczęściej na początku. W podróży najważniejsze jest zapamiętanie całych fraz, bo gramatyka przyjdzie naturalnie z powtarzaniem.`, practice: [`Zapytaj po arabsku, gdzie jest hotel.`,`Zapytaj, ile coś kosztuje.`,`Utwórz pytanie z هل.`,`Wskaż przedmiot i powiedz هذا.`,`Przećwicz trzy pytania, które przydadzą się w mieście.`]},{day: 4, title: `Liczby od 0 do 10`, title_native: `الأرقام من صفر إلى عشرة`, focus: `Kupujesz wodę i bilety w Kairze, więc potrzebujesz rozumieć małe liczby. Dziś ćwiczysz liczenie, ceny i ilości.`, vocab: [{ar: `صفر`, pl: `zero`, ipa: `sifr`},{ar: `واحد`, pl: `jeden`, ipa: `wa-hid`},{ar: `اثنان`, pl: `dwa`, ipa: `is-nan`},{ar: `ثلاثة`, pl: `trzy`, ipa: `sa-la-sa`},{ar: `أربعة`, pl: `cztery`, ipa: `ar-ba-a`},{ar: `خمسة`, pl: `pięć`, ipa: `cham-sa`},{ar: `ستة`, pl: `sześć`, ipa: `sit-ta`},{ar: `سبعة`, pl: `siedem`, ipa: `sab-a`},{ar: `ثمانية`, pl: `osiem`, ipa: `sa-ma-ni-ja`},{ar: `تسعة`, pl: `dziewięć`, ipa: `tis-a`},{ar: `عشرة`, pl: `dziesięć`, ipa: `a-sza-ra`}], phrases: [{ar: `واحد من فضلك`, pl: `Jeden, proszę`, ipa: `wa-hid min fad-lik`},{ar: `اثنان من فضلك`, pl: `Dwa, proszę`, ipa: `is-nan min fad-lik`},{ar: `كم العدد؟`, pl: `Jaka liczba?`, ipa: `kam al-a-dad`},{ar: `أريد ثلاثة`, pl: `Chcę trzy`, ipa: `u-rid sa-la-sa`},{ar: `هذا خمسة`, pl: `To jest pięć`, ipa: `ha-za cham-sa`},{ar: `عندي عشرة`, pl: `Mam dziesięć`, ipa: `in-di a-sza-ra`}], grammar: `Liczby po arabsku mają osobne formy, które później mogą zmieniać się z rzeczownikami, ale na start ucz się ich samodzielnie. W sklepie często wystarczy liczba plus من فضلك. Słowo أريد oznacza „chcę” i jest bardzo praktyczne przy zamawianiu.`, practice: [`Policz od صفر do عشرة.`,`Zamów jedną wodę, używając واحد من فضلك.`,`Powiedz „chcę trzy”.`,`Zapytaj „ile?” słowem كم.`,`Przećwicz liczby 1, 2, 3, 5 i 10 na głos.`]},{day: 5, title: `Uprzejmość i przeprosiny`, title_native: `المجاملة والاعتذار`, focus: `W zatłoczonym metrze w Dosze chcesz być uprzejmy i spokojny. Uczysz się przepraszać, prosić o pomoc i reagować grzecznie.`, vocab: [{ar: `آسف`, pl: `przepraszam / przykro mi`, ipa: `a-sif`},{ar: `آسفة`, pl: `przepraszam, mówi kobieta`, ipa: `a-si-fa`},{ar: `من فضلك`, pl: `proszę`, ipa: `min fad-lik`},{ar: `ممكن`, pl: `czy można / możliwe`, ipa: `mum-kin`},{ar: `مساعدة`, pl: `pomoc`, ipa: `mu-sa-a-da`},{ar: `مشكلة`, pl: `problem`, ipa: `musz-ki-la`},{ar: `لا مشكلة`, pl: `nie ma problemu`, ipa: `la musz-ki-la`},{ar: `تفضل`, pl: `proszę, oto`, ipa: `ta-fad-dal`},{ar: `لحظة`, pl: `chwila`, ipa: `lah-za`},{ar: `ببطء`, pl: `powoli`, ipa: `bi-but`}], phrases: [{ar: `آسف، لو سمحت`, pl: `Przepraszam, proszę pana/pani`, ipa: `a-sif, lau sa-maht`},{ar: `هل ممكن؟`, pl: `Czy można?`, ipa: `hal mum-kin`},{ar: `أحتاج مساعدة`, pl: `Potrzebuję pomocy`, ipa: `ah-tadż mu-sa-a-da`},{ar: `لا مشكلة`, pl: `Nie ma problemu`, ipa: `la musz-ki-la`},{ar: `لحظة من فضلك`, pl: `Chwileczkę, proszę`, ipa: `lah-za min fad-lik`},{ar: `تكلم ببطء من فضلك`, pl: `Mów powoli, proszę`, ipa: `ta-kal-lam bi-but min fad-lik`}], grammar: `W arabskim uprzejmość często wyraża się przez gotowe zwroty, takie jak من فضلك i لو سمحت. Słowo آسف może oznaczać „przepraszam” lub „przykro mi”, zależnie od sytuacji. Kobieta mówiąca o sobie często używa formy آسفة.`, practice: [`Poproś kogoś, aby mówił powoli.`,`Powiedz, że potrzebujesz pomocy.`,`Przećwicz آسف i آسفة.`,`Zareaguj na drobny problem słowami لا مشكلة.`,`Napisz krótką scenkę w metrze z użyciem من فضلك.`]},{day: 6, title: `Na lotnisku`, title_native: `في المطار`, focus: `Przylatujesz do Bejrutu i musisz przejść przez lotnisko. Uczysz się słów związanych z paszportem, bagażem, bramką i kontrolą.`, vocab: [{ar: `مطار`, pl: `lotnisko`, ipa: `ma-tar`},{ar: `طائرة`, pl: `samolot`, ipa: `ta-i-ra`},{ar: `رحلة`, pl: `lot / podróż`, ipa: `rih-la`},{ar: `جواز السفر`, pl: `paszport`, ipa: `dża-waz as-sa-far`},{ar: `حقيبة`, pl: `torba / walizka`, ipa: `ha-ki-ba`},{ar: `أمتعة`, pl: `bagaże`, ipa: `am-ti-a`},{ar: `بوابة`, pl: `bramka`, ipa: `ba-wa-ba`},{ar: `تذكرة`, pl: `bilet`, ipa: `taz-ki-ra`},{ar: `تأشيرة`, pl: `wiza`, ipa: `ta-szi-ra`},{ar: `خروج`, pl: `wyjście`, ipa: `chu-rudż`}], phrases: [{ar: `أين الجوازات؟`, pl: `Gdzie jest kontrola paszportowa?`, ipa: `aj-na al-dża-wa-zat`},{ar: `هذه حقيبتي`, pl: `To moja torba`, ipa: `ha-zi-hi ha-ki-ba-ti`},{ar: `عندي تذكرة`, pl: `Mam bilet`, ipa: `in-di taz-ki-ra`},{ar: `أين البوابة؟`, pl: `Gdzie jest bramka?`, ipa: `aj-na al-ba-wa-ba`},{ar: `أحتاج تأشيرة؟`, pl: `Czy potrzebuję wizy?`, ipa: `ah-tadż ta-szi-ra`},{ar: `أين الخروج؟`, pl: `Gdzie jest wyjście?`, ipa: `aj-na al-chu-rudż`}], grammar: `هذه oznacza „ta/to” dla rodzaju żeńskiego, a هذا dla męskiego. Wiele rzeczy po arabsku ma rodzaj gramatyczny, np. حقيبة jest żeńska, więc mówimy هذه حقيبة. Na początku zapamiętuj po prostu całe frazy z rzeczownikiem.`, practice: [`Zapytaj, gdzie jest wyjście.`,`Powiedz: „To moja torba”.`,`Zapytaj o bramkę.`,`Powiedz, że masz bilet.`,`Wyobraź sobie odprawę i wypowiedz trzy lotniskowe frazy.`]},{day: 7, title: `Hotel i zameldowanie`, title_native: `الفندق وتسجيل الدخول`, focus: `Meldujesz się w hotelu w Abu Zabi. Uczysz się pytać o rezerwację, pokój, klucz i śniadanie.`, vocab: [{ar: `فندق`, pl: `hotel`, ipa: `fun-duk`},{ar: `حجز`, pl: `rezerwacja`, ipa: `hadżz`},{ar: `غرفة`, pl: `pokój`, ipa: `ghur-fa`},{ar: `مفتاح`, pl: `klucz`, ipa: `mif-tah`},{ar: `استقبال`, pl: `recepcja`, ipa: `is-tik-bal`},{ar: `ليلة`, pl: `noc`, ipa: `laj-la`},{ar: `سرير`, pl: `łóżko`, ipa: `sa-rir`},{ar: `حمام`, pl: `łazienka`, ipa: `ham-mam`},{ar: `إفطار`, pl: `śniadanie`, ipa: `if-tar`},{ar: `مصعد`, pl: `winda`, ipa: `mis-ad`}], phrases: [{ar: `عندي حجز`, pl: `Mam rezerwację`, ipa: `in-di hadżz`},{ar: `أريد غرفة`, pl: `Chcę pokój`, ipa: `u-rid ghur-fa`},{ar: `أين المصعد؟`, pl: `Gdzie jest winda?`, ipa: `aj-na al-mis-ad`},{ar: `هل الإفطار مشمول؟`, pl: `Czy śniadanie jest wliczone?`, ipa: `hal al-if-tar masz-mul`},{ar: `أحتاج المفتاح`, pl: `Potrzebuję klucza`, ipa: `ah-tadż al-mif-tah`},{ar: `ليلة واحدة`, pl: `Jedna noc`, ipa: `laj-la wa-hi-da`}], grammar: `عندي dosłownie znaczy „przy mnie”, ale w praktyce oznacza „mam”. Możesz używać tego wzoru w hotelu: عندي حجز, عندي جواز سفر, عندي تذكرة. To jeden z najważniejszych praktycznych zwrotów dla podróżnika.`, practice: [`Powiedz w recepcji: „Mam rezerwację”.`,`Zapytaj, czy śniadanie jest wliczone.`,`Poproś o klucz.`,`Powiedz „jedna noc”.`,`Połącz słowa فندق, غرفة i مفتاح w krótkie zdania.`]},{day: 8, title: `Kierunki i orientacja`, title_native: `الاتجاهات والمكان`, focus: `Chodzisz po medynie w Fezie i łatwo się zgubić. Uczysz się pytać o drogę i rozumieć: prosto, w lewo, w prawo, blisko i daleko.`, vocab: [{ar: `يمين`, pl: `prawo`, ipa: `ja-min`},{ar: `يسار`, pl: `lewo`, ipa: `ja-sar`},{ar: `مستقيم`, pl: `prosto`, ipa: `mus-ta-kim`},{ar: `قريب`, pl: `blisko`, ipa: `ka-rib`},{ar: `بعيد`, pl: `daleko`, ipa: `ba-id`},{ar: `شارع`, pl: `ulica`, ipa: `sza-ri`},{ar: `ساحة`, pl: `plac`, ipa: `sa-ha`},{ar: `خريطة`, pl: `mapa`, ipa: `cha-ri-ta`},{ar: `محطة`, pl: `stacja`, ipa: `ma-hat-ta`},{ar: `مخرج`, pl: `wyjście`, ipa: `mach-radż`}], phrases: [{ar: `أين هذا المكان؟`, pl: `Gdzie jest to miejsce?`, ipa: `aj-na ha-za al-ma-kan`},{ar: `اذهب مستقيمًا`, pl: `Idź prosto`, ipa: `iz-hab mus-ta-ki-man`},{ar: `إلى اليمين`, pl: `W prawo`, ipa: `i-la al-ja-min`},{ar: `إلى اليسار`, pl: `W lewo`, ipa: `i-la al-ja-sar`},{ar: `هل هو قريب؟`, pl: `Czy to jest blisko?`, ipa: `hal hu-wa ka-rib`},{ar: `أين المحطة؟`, pl: `Gdzie jest stacja?`, ipa: `aj-na al-ma-hat-ta`}], grammar: `إلى oznacza „do” lub „w kierunku”, dlatego pojawia się w zwrotach إلى اليمين i إلى اليسار. Słowo أين jest bardzo użyteczne w pytaniach o lokalizację. W praktyce wystarczy połączyć أين z miejscem, którego szukasz.`, practice: [`Zapytaj, gdzie jest stacja.`,`Powiedz komuś, aby szedł prosto.`,`Rozróżnij يمين i يسار.`,`Zapytaj, czy miejsce jest blisko.`,`Opisz prostą trasę: prosto, potem w prawo.`]},{day: 9, title: `Transport miejski`, title_native: `المواصلات في المدينة`, focus: `Korzystasz z metra i autobusu w Kairze. Uczysz się kupować bilet, pytać o stację i sprawdzać kierunek jazdy.`, vocab: [{ar: `حافلة`, pl: `autobus`, ipa: `ha-fi-la`},{ar: `مترو`, pl: `metro`, ipa: `mit-ro`},{ar: `قطار`, pl: `pociąg`, ipa: `ki-tar`},{ar: `سيارة أجرة`, pl: `taksówka`, ipa: `saj-ja-ra udż-ra`},{ar: `تذكرة`, pl: `bilet`, ipa: `taz-ki-ra`},{ar: `محطة`, pl: `przystanek / stacja`, ipa: `ma-hat-ta`},{ar: `خط`, pl: `linia`, ipa: `chatt`},{ar: `اتجاه`, pl: `kierunek`, ipa: `it-ti-dżah`},{ar: `رحلة`, pl: `przejazd / podróż`, ipa: `rih-la`},{ar: `سائق`, pl: `kierowca`, ipa: `sa-ik`}], phrases: [{ar: `أريد تذكرة`, pl: `Chcę bilet`, ipa: `u-rid taz-ki-ra`},{ar: `إلى أين يذهب هذا المترو؟`, pl: `Dokąd jedzie to metro?`, ipa: `i-la aj-na jaz-hab ha-za al-mit-ro`},{ar: `هل هذه المحطة؟`, pl: `Czy to ta stacja?`, ipa: `hal ha-zi-hi al-ma-hat-ta`},{ar: `كم سعر التذكرة؟`, pl: `Ile kosztuje bilet?`, ipa: `kam si-r at-taz-ki-ra`},{ar: `أين موقف الحافلة؟`, pl: `Gdzie jest przystanek autobusu?`, ipa: `aj-na mau-kif al-ha-fi-la`},{ar: `أريد سيارة أجرة`, pl: `Chcę taksówkę`, ipa: `u-rid saj-ja-ra udż-ra`}], grammar: `هذا i هذه pomagają pytać o konkretne rzeczy: هذا المترو, هذه المحطة. W arabskim rzeczowniki z rodzajnikiem ال są określone, podobnie jak „ten/ta” w kontekście. Dlatego المحطة oznacza „stacja” lub „ta stacja”, zależnie od sytuacji.`, practice: [`Kup bilet, mówiąc أريد تذكرة.`,`Zapytaj o cenę biletu.`,`Zapytaj, czy to właściwa stacja.`,`Powiedz, że chcesz taksówkę.`,`Ułóż krótką rozmowę z kierowcą autobusu.`]},{day: 10, title: `Taksówka i przejazd`, title_native: `سيارة الأجرة والرحلة`, focus: `Bierzesz taksówkę w Maskacie i chcesz jasno podać adres. Uczysz się mówić „proszę tutaj”, „ile kosztuje” i „proszę zatrzymać się”.`, vocab: [{ar: `عنوان`, pl: `adres`, ipa: `un-wan`},{ar: `مركز`, pl: `centrum`, ipa: `mar-kaz`},{ar: `فندق`, pl: `hotel`, ipa: `fun-duk`},{ar: `متحف`, pl: `muzeum`, ipa: `mat-haf`},{ar: `سوق`, pl: `targ`, ipa: `suk`},{ar: `توقف`, pl: `zatrzymaj się`, ipa: `ta-wak-kaf`},{ar: `هنا`, pl: `tutaj`, ipa: `hu-na`},{ar: `هناك`, pl: `tam`, ipa: `hu-nak`},{ar: `عداد`, pl: `taksometr`, ipa: `ad-dad`},{ar: `سعر`, pl: `cena`, ipa: `si-r`}], phrases: [{ar: `إلى هذا العنوان من فضلك`, pl: `Pod ten adres, proszę`, ipa: `i-la ha-za al-un-wan min fad-lik`},{ar: `كم السعر؟`, pl: `Ile kosztuje?`, ipa: `kam as-si-r`},{ar: `هل عندك عداد؟`, pl: `Czy ma pan taksometr?`, ipa: `hal in-dak ad-dad`},{ar: `توقف هنا من فضلك`, pl: `Proszę zatrzymać się tutaj`, ipa: `ta-wak-kaf hu-na min fad-lik`},{ar: `أريد الذهاب إلى السوق`, pl: `Chcę jechać na targ`, ipa: `u-rid az-zi-hab i-la as-suk`},{ar: `هل هذا بعيد؟`, pl: `Czy to daleko?`, ipa: `hal ha-za ba-id`}], grammar: `أريد plus bezokolicznik rzeczownikowy, np. الذهاب, pozwala mówić „chcę iść/jechać”. W codziennej rozmowie często wystarczy أريد إلى السوق, ale pełniejsza forma أريد الذهاب إلى السوق brzmi bardziej standardowo. W taksówce używaj krótkich zdań i wskazuj adres na telefonie.`, practice: [`Powiedz kierowcy: „Pod ten adres, proszę”.`,`Zapytaj, czy ma taksometr.`,`Poproś, aby zatrzymał się tutaj.`,`Powiedz, że chcesz jechać na targ.`,`Przećwicz słowa هنا i هناك.`]},{day: 11, title: `Kawiarnia i napoje`, title_native: `في المقهى والمشروبات`, focus: `Siadasz w kawiarni w Tunisie i zamawiasz kawę, herbatę lub wodę. Uczysz się mówić „poproszę”, „bez cukru” i „rachunek”.`, vocab: [{ar: `مقهى`, pl: `kawiarnia`, ipa: `mak-ha`},{ar: `قهوة`, pl: `kawa`, ipa: `kah-wa`},{ar: `شاي`, pl: `herbata`, ipa: `szaj`},{ar: `ماء`, pl: `woda`, ipa: `ma`},{ar: `سكر`, pl: `cukier`, ipa: `suk-kar`},{ar: `حليب`, pl: `mleko`, ipa: `ha-lib`},{ar: `كوب`, pl: `kubek / szklanka`, ipa: `kub`},{ar: `بارد`, pl: `zimny`, ipa: `ba-rid`},{ar: `ساخن`, pl: `gorący`, ipa: `sa-chin`},{ar: `فاتورة`, pl: `rachunek`, ipa: `fa-tu-ra`}], phrases: [{ar: `أريد قهوة من فضلك`, pl: `Poproszę kawę`, ipa: `u-rid kah-wa min fad-lik`},{ar: `شاي بدون سكر`, pl: `Herbata bez cukru`, ipa: `szaj bi-dun suk-kar`},{ar: `ماء بارد من فضلك`, pl: `Zimną wodę, proszę`, ipa: `ma ba-rid min fad-lik`},{ar: `هل عندكم حليب؟`, pl: `Czy macie mleko?`, ipa: `hal in-da-kum ha-lib`},{ar: `الفاتورة من فضلك`, pl: `Rachunek, proszę`, ipa: `al-fa-tu-ra min fad-lik`},{ar: `قهوة واحدة`, pl: `Jedna kawa`, ipa: `kah-wa wa-hi-da`}], grammar: `بدون oznacza „bez” i jest bardzo przydatne w jedzeniu i piciu: بدون سكر, بدون حليب, بدون لحم. Słowo عندكم oznacza „czy macie / u was jest”. W kawiarni możesz używać go, pytając o składniki lub dostępne napoje.`, practice: [`Zamów kawę po arabsku.`,`Zamów herbatę bez cukru.`,`Poproś o zimną wodę.`,`Zapytaj, czy mają mleko.`,`Poproś o rachunek.`]},{day: 12, title: `Restauracja i zamawianie jedzenia`, title_native: `في المطعم وطلب الطعام`, focus: `Jesz kolację w restauracji w Ammanie i chcesz zamówić proste dania. Uczysz się pytać o menu, mięso, ryż i danie wegetariańskie.`, vocab: [{ar: `مطعم`, pl: `restauracja`, ipa: `mat-am`},{ar: `قائمة الطعام`, pl: `menu`, ipa: `ka-i-mat at-ta-am`},{ar: `طعام`, pl: `jedzenie`, ipa: `ta-am`},{ar: `دجاج`, pl: `kurczak`, ipa: `da-dżadż`},{ar: `لحم`, pl: `mięso`, ipa: `lahm`},{ar: `سمك`, pl: `ryba`, ipa: `sa-mak`},{ar: `أرز`, pl: `ryż`, ipa: `urz`},{ar: `سلطة`, pl: `sałatka`, ipa: `sa-la-ta`},{ar: `خبز`, pl: `chleb`, ipa: `chubz`},{ar: `نباتي`, pl: `wegetariański`, ipa: `na-ba-ti`}], phrases: [{ar: `أريد قائمة الطعام`, pl: `Poproszę menu`, ipa: `u-rid ka-i-mat at-ta-am`},{ar: `ماذا تنصح؟`, pl: `Co polecasz?`, ipa: `ma-za tan-sah`},{ar: `أريد دجاجًا مع أرز`, pl: `Chcę kurczaka z ryżem`, ipa: `u-rid da-dża-dżan ma-a urz`},{ar: `هل عندكم طعام نباتي؟`, pl: `Czy macie jedzenie wegetariańskie?`, ipa: `hal in-da-kum ta-am na-ba-ti`},{ar: `بدون لحم من فضلك`, pl: `Bez mięsa, proszę`, ipa: `bi-dun lahm min fad-lik`},{ar: `كان لذيذًا`, pl: `Było smaczne`, ipa: `kan la-zi-zan`}], grammar: `مع oznacza „z” w sensie „razem z”, np. دجاج مع أرز. بدون oznacza „bez” i często ratuje sytuację przy diecie lub alergiach. W restauracji możesz mówić krótkimi frazami, a obsługa zwykle zrozumie intencję.`, practice: [`Poproś o menu.`,`Zapytaj, co kelner poleca.`,`Zamów kurczaka z ryżem.`,`Zapytaj o danie wegetariańskie.`,`Powiedz, że było smaczne.`]},{day: 13, title: `Preferencje i alergie`, title_native: `التفضيلات والحساسية`, focus: `Podczas posiłku w Dubaju musisz powiedzieć, czego nie jesz lub na co masz alergię. Uczysz się mówić „nie jem”, „mam alergię” i „czy to zawiera...”.`, vocab: [{ar: `حساسية`, pl: `alergia`, ipa: `ha-sa-si-ja`},{ar: `فول سوداني`, pl: `orzeszki ziemne`, ipa: `ful su-da-ni`},{ar: `جلوتين`, pl: `gluten`, ipa: `dżu-lu-tin`},{ar: `حليب`, pl: `mleko`, ipa: `ha-lib`},{ar: `بيض`, pl: `jajka`, ipa: `bajd`},{ar: `بحرية`, pl: `morskie`, ipa: `bah-ri-ja`},{ar: `حار`, pl: `ostre`, ipa: `har`},{ar: `خفيف`, pl: `łagodne`, ipa: `cha-fif`},{ar: `آكل`, pl: `jem`, ipa: `a-kul`},{ar: `يحتوي`, pl: `zawiera`, ipa: `jah-ta-wi`}], phrases: [{ar: `عندي حساسية`, pl: `Mam alergię`, ipa: `in-di ha-sa-si-ja`},{ar: `لا آكل اللحم`, pl: `Nie jem mięsa`, ipa: `la a-kul al-lahm`},{ar: `هل يحتوي على حليب؟`, pl: `Czy to zawiera mleko?`, ipa: `hal jah-ta-wi a-la ha-lib`},{ar: `هل هذا حار؟`, pl: `Czy to jest ostre?`, ipa: `hal ha-za har`},{ar: `أريد طعامًا خفيفًا`, pl: `Chcę łagodne jedzenie`, ipa: `u-rid ta-a-man cha-fi-fan`},{ar: `بدون فول سوداني`, pl: `Bez orzeszków ziemnych`, ipa: `bi-dun ful su-da-ni`}], grammar: `لا przed czasownikiem tworzy proste przeczenie w czasie teraźniejszym: لا آكل znaczy „nie jem”. عندي حساسية to praktyczna fraza oznaczająca „mam alergię”. W razie alergii najlepiej pokazać napisane słowo kelnerowi i powtórzyć بدون.`, practice: [`Powiedz: „Mam alergię”.`,`Powiedz: „Nie jem mięsa”.`,`Zapytaj, czy danie zawiera mleko.`,`Zapytaj, czy potrawa jest ostra.`,`Zamów coś łagodnego.`]},{day: 14, title: `Zakupy na targu`, title_native: `التسوق في السوق`, focus: `Odwiedzasz tradycyjny targ w Marrakeszu. Uczysz się pytać o cenę, rozmiar, kolor i mówić, że tylko oglądasz.`, vocab: [{ar: `سوق`, pl: `targ`, ipa: `suk`},{ar: `سعر`, pl: `cena`, ipa: `si-r`},{ar: `غالي`, pl: `drogi`, ipa: `gha-li`},{ar: `رخيص`, pl: `tani`, ipa: `ra-chis`},{ar: `لون`, pl: `kolor`, ipa: `laun`},{ar: `حجم`, pl: `rozmiar`, ipa: `hadżm`},{ar: `كبير`, pl: `duży`, ipa: `ka-bir`},{ar: `صغير`, pl: `mały`, ipa: `sa-ghir`},{ar: `أشتري`, pl: `kupuję`, ipa: `asz-ta-ri`},{ar: `أنظر`, pl: `oglądam`, ipa: `an-zur`}], phrases: [{ar: `كم السعر؟`, pl: `Ile kosztuje?`, ipa: `kam as-si-r`},{ar: `هذا غالي`, pl: `To jest drogie`, ipa: `ha-za gha-li`},{ar: `هل عندك لون آخر؟`, pl: `Czy masz inny kolor?`, ipa: `hal in-dak laun a-char`},{ar: `أريد حجمًا صغيرًا`, pl: `Chcę mały rozmiar`, ipa: `u-rid hadż-man sa-ghi-ran`},{ar: `أنا أنظر فقط`, pl: `Tylko oglądam`, ipa: `a-na an-zur fa-kat`},{ar: `سآخذه`, pl: `Wezmę to`, ipa: `sa-a-chu-zu-hu`}], grammar: `W wielu krajach arabskich targowanie się na bazarach jest normalne, ale warto robić to z uśmiechem. غالي oznacza „drogi”, a możesz powiedzieć هذا غالي jako łagodny początek negocjacji. فقط znaczy „tylko” i pasuje do zdania أنا أنظر فقط.`, practice: [`Zapytaj o cenę.`,`Powiedz, że coś jest drogie.`,`Zapytaj o inny kolor.`,`Powiedz, że tylko oglądasz.`,`Powiedz, że weźmiesz produkt.`]},{day: 15, title: `Kolory i opisy`, title_native: `الألوان والوصف`, focus: `Kupujesz ubrania w centrum handlowym w Rijadzie. Uczysz się podstawowych kolorów i prostych przymiotników.`, vocab: [{ar: `أبيض`, pl: `biały`, ipa: `ab-jad`},{ar: `أسود`, pl: `czarny`, ipa: `as-wad`},{ar: `أحمر`, pl: `czerwony`, ipa: `ah-mar`},{ar: `أزرق`, pl: `niebieski`, ipa: `az-rak`},{ar: `أخضر`, pl: `zielony`, ipa: `ach-dar`},{ar: `أصفر`, pl: `żółty`, ipa: `as-far`},{ar: `جميل`, pl: `piękny`, ipa: `dża-mil`},{ar: `جديد`, pl: `nowy`, ipa: `dża-did`},{ar: `قديم`, pl: `stary`, ipa: `ka-dim`},{ar: `مناسب`, pl: `odpowiedni`, ipa: `mu-na-sib`}], phrases: [{ar: `أريد اللون الأزرق`, pl: `Chcę kolor niebieski`, ipa: `u-rid al-laun al-az-rak`},{ar: `هل عندك أسود؟`, pl: `Czy masz czarny?`, ipa: `hal in-dak as-wad`},{ar: `هذا جميل`, pl: `To jest piękne`, ipa: `ha-za dża-mil`},{ar: `هذا مناسب`, pl: `To pasuje / jest odpowiednie`, ipa: `ha-za mu-na-sib`},{ar: `أريد شيئًا جديدًا`, pl: `Chcę coś nowego`, ipa: `u-rid szaj-an dża-di-dan`},{ar: `ليس هذا اللون`, pl: `Nie ten kolor`, ipa: `lajsa ha-za al-laun`}], grammar: `Przymiotniki w arabskim zwykle stoją po rzeczowniku, np. لون أزرق znaczy „kolor niebieski”. W prostych zdaniach możesz używać هذا جميل lub هذا مناسب bez skomplikowanej odmiany. ليس pomaga powiedzieć „nie jest”, np. ليس هذا اللون.`, practice: [`Poproś o kolor niebieski.`,`Zapytaj, czy mają czarny.`,`Powiedz, że coś jest ładne.`,`Powiedz: „Nie ten kolor”.`,`Opisz jeden przedmiot dwoma arabskimi słowami.`]},{day: 16, title: `Dni tygodnia i godziny`, title_native: `أيام الأسبوع والوقت`, focus: `Planujesz zwiedzanie w Kairze i musisz znać dni oraz podstawowe godziny. Uczysz się mówić „dzisiaj”, „jutro”, „o której” i „otwarte”.`, vocab: [{ar: `اليوم`, pl: `dzisiaj`, ipa: `al-jaum`},{ar: `غدًا`, pl: `jutro`, ipa: `gha-dan`},{ar: `أمس`, pl: `wczoraj`, ipa: `ams`},{ar: `ساعة`, pl: `godzina`, ipa: `sa-a`},{ar: `دقيقة`, pl: `minuta`, ipa: `da-ki-ka`},{ar: `الأحد`, pl: `niedziela`, ipa: `al-a-had`},{ar: `الاثنين`, pl: `poniedziałek`, ipa: `al-is-najn`},{ar: `الثلاثاء`, pl: `wtorek`, ipa: `as-su-la-sa`},{ar: `الجمعة`, pl: `piątek`, ipa: `al-dżu-mu-a`},{ar: `مفتوح`, pl: `otwarte`, ipa: `maf-tuh`}], phrases: [{ar: `ما الوقت الآن؟`, pl: `Która jest teraz godzina?`, ipa: `ma al-wakt al-an`},{ar: `متى يفتح؟`, pl: `Kiedy otwiera?`, ipa: `ma-ta jaf-tah`},{ar: `متى يغلق؟`, pl: `Kiedy zamyka?`, ipa: `ma-ta jagh-lik`},{ar: `هل هو مفتوح اليوم؟`, pl: `Czy jest dziś otwarte?`, ipa: `hal hu-wa maf-tuh al-jaum`},{ar: `غدًا صباحًا`, pl: `Jutro rano`, ipa: `gha-dan sa-ba-han`},{ar: `في الساعة الثالثة`, pl: `O trzeciej`, ipa: `fi as-sa-a as-sa-li-sa`}], grammar: `في może oznaczać „w” albo „o” przy czasie: في الساعة الثالثة to „o trzeciej”. Dni tygodnia często mają rodzajnik ال. W podróży szczególnie przydatne są pytania متى يفتح؟ i متى يغلق؟.`, practice: [`Zapytaj, która jest godzina.`,`Zapytaj, kiedy muzeum się otwiera.`,`Powiedz „jutro rano”.`,`Powiedz „o trzeciej”.`,`Zapytaj, czy miejsce jest dziś otwarte.`]},{day: 17, title: `Zwiedzanie i atrakcje`, title_native: `السياحة والمعالم`, focus: `Zwiedzasz stare miasto w Jerozolimie i chcesz pytać o zabytki, bilety i zdjęcia. Uczysz się słów związanych z turystyką.`, vocab: [{ar: `متحف`, pl: `muzeum`, ipa: `mat-haf`},{ar: `قلعة`, pl: `zamek / forteca`, ipa: `kal-a`},{ar: `مسجد`, pl: `meczet`, ipa: `mas-dżid`},{ar: `كنيسة`, pl: `kościół`, ipa: `ka-ni-sa`},{ar: `معبد`, pl: `świątynia`, ipa: `ma-bad`},{ar: `صورة`, pl: `zdjęcie`, ipa: `su-ra`},{ar: `دليل`, pl: `przewodnik`, ipa: `da-lil`},{ar: `تاريخ`, pl: `historia`, ipa: `ta-rich`},{ar: `تذكرة دخول`, pl: `bilet wstępu`, ipa: `taz-ki-rat du-chul`},{ar: `ممنوع`, pl: `zakazane`, ipa: `mam-nu`}], phrases: [{ar: `أين المتحف؟`, pl: `Gdzie jest muzeum?`, ipa: `aj-na al-mat-haf`},{ar: `هل التصوير مسموح؟`, pl: `Czy fotografowanie jest dozwolone?`, ipa: `hal at-tas-wir mas-muh`},{ar: `أريد تذكرة دخول`, pl: `Chcę bilet wstępu`, ipa: `u-rid taz-ki-rat du-chul`},{ar: `هل عندكم دليل؟`, pl: `Czy macie przewodnika?`, ipa: `hal in-da-kum da-lil`},{ar: `هذا المكان جميل`, pl: `To miejsce jest piękne`, ipa: `ha-za al-ma-kan dża-mil`},{ar: `التصوير ممنوع`, pl: `Fotografowanie jest zakazane`, ipa: `at-tas-wir mam-nu`}], grammar: `مسموح znaczy „dozwolone”, a ممنوع znaczy „zakazane”. W miejscach religijnych i historycznych zawsze zwracaj uwagę na znaki oraz zasady ubioru. Pytanie هل التصوير مسموح؟ jest uprzejme i bardzo praktyczne.`, practice: [`Zapytaj, czy fotografowanie jest dozwolone.`,`Poproś o bilet wstępu.`,`Zapytaj o przewodnika.`,`Powiedz, że miejsce jest piękne.`,`Przećwicz słowa مسجد, كنيسة i متحف.`]},{day: 18, title: `Plaża i pogoda`, title_native: `الشاطئ والطقس`, focus: `Jesteś nad Morzem Czerwonym w Akabie. Uczysz się mówić o pogodzie, plaży, słońcu, wodzie i planach na zewnątrz.`, vocab: [{ar: `شاطئ`, pl: `plaża`, ipa: `sza-ti`},{ar: `بحر`, pl: `morze`, ipa: `bahr`},{ar: `شمس`, pl: `słońce`, ipa: `szams`},{ar: `طقس`, pl: `pogoda`, ipa: `taks`},{ar: `حار`, pl: `gorąco`, ipa: `har`},{ar: `بارد`, pl: `zimno`, ipa: `ba-rid`},{ar: `جميل`, pl: `piękny`, ipa: `dża-mil`},{ar: `رياح`, pl: `wiatr`, ipa: `ri-jah`},{ar: `مطر`, pl: `deszcz`, ipa: `ma-tar`},{ar: `ماء`, pl: `woda`, ipa: `ma`}], phrases: [{ar: `الطقس جميل`, pl: `Pogoda jest piękna`, ipa: `at-taks dża-mil`},{ar: `اليوم حار`, pl: `Dzisiaj jest gorąco`, ipa: `al-jaum har`},{ar: `أين الشاطئ؟`, pl: `Gdzie jest plaża?`, ipa: `aj-na asz-sza-ti`},{ar: `أريد ماء`, pl: `Chcę wodę`, ipa: `u-rid ma`},{ar: `هل البحر قريب؟`, pl: `Czy morze jest blisko?`, ipa: `hal al-bahr ka-rib`},{ar: `هناك رياح`, pl: `Jest wiatr`, ipa: `hu-nak ri-jah`}], grammar: `W opisie pogody często używa się prostych zdań bez czasownika „być”: الطقس جميل, اليوم حار. Słowo هناك oznacza „jest / znajduje się tam” i pomaga mówić o zjawiskach lub miejscach. Możesz powiedzieć هناك مطر, gdy chcesz powiedzieć, że pada deszcz.`, practice: [`Powiedz, że pogoda jest piękna.`,`Zapytaj, gdzie jest plaża.`,`Powiedz, że dzisiaj jest gorąco.`,`Zapytaj, czy morze jest blisko.`,`Opisz pogodę trzema arabskimi słowami.`]},{day: 19, title: `Zdrowie i apteka`, title_native: `الصحة والصيدلية`, focus: `Źle się czujesz w Casablance i idziesz do apteki. Uczysz się mówić o bólu, gorączce, lekarstwie i potrzebie pomocy.`, vocab: [{ar: `صيدلية`, pl: `apteka`, ipa: `saj-da-li-ja`},{ar: `طبيب`, pl: `lekarz`, ipa: `ta-bib`},{ar: `دواء`, pl: `lekarstwo`, ipa: `da-wa`},{ar: `ألم`, pl: `ból`, ipa: `a-lam`},{ar: `رأس`, pl: `głowa`, ipa: `ras`},{ar: `معدة`, pl: `żołądek`, ipa: `ma-i-da`},{ar: `حمى`, pl: `gorączka`, ipa: `hum-ma`},{ar: `زكام`, pl: `przeziębienie`, ipa: `zu-kam`},{ar: `مريض`, pl: `chory`, ipa: `ma-rid`},{ar: `مستشفى`, pl: `szpital`, ipa: `mus-tasz-fa`}], phrases: [{ar: `أين الصيدلية؟`, pl: `Gdzie jest apteka?`, ipa: `aj-na as-saj-da-li-ja`},{ar: `عندي ألم في الرأس`, pl: `Boli mnie głowa`, ipa: `in-di a-lam fi ar-ras`},{ar: `عندي ألم في المعدة`, pl: `Boli mnie żołądek`, ipa: `in-di a-lam fi al-ma-i-da`},{ar: `أحتاج دواء`, pl: `Potrzebuję lekarstwa`, ipa: `ah-tadż da-wa`},{ar: `هل أحتاج طبيبًا؟`, pl: `Czy potrzebuję lekarza?`, ipa: `hal ah-tadż ta-bi-ban`},{ar: `أين المستشفى؟`, pl: `Gdzie jest szpital?`, ipa: `aj-na al-mus-tasz-fa`}], grammar: `عندي ألم في... to bardzo przydatny wzór: „mam ból w...”. Po في podajesz część ciała, np. الرأس lub المعدة. W sytuacjach zdrowotnych mów wolno, pokazuj objaw i w razie potrzeby użyj tłumacza na telefonie.`, practice: [`Zapytaj, gdzie jest apteka.`,`Powiedz, że boli cię głowa.`,`Powiedz, że potrzebujesz lekarstwa.`,`Zapytaj, czy potrzebujesz lekarza.`,`Zapytaj, gdzie jest szpital.`]},{day: 20, title: `Nagłe sytuacje`, title_native: `الحالات الطارئة`, focus: `W podróży może zdarzyć się problem, więc uczysz się wzywać pomoc. Dziś ćwiczysz zwroty do policji, lekarza i przypadkowych przechodniów.`, vocab: [{ar: `مساعدة`, pl: `pomoc`, ipa: `mu-sa-a-da`},{ar: `شرطة`, pl: `policja`, ipa: `szur-ta`},{ar: `إسعاف`, pl: `pogotowie`, ipa: `is-af`},{ar: `خطر`, pl: `niebezpieczeństwo`, ipa: `cha-tar`},{ar: `سرقة`, pl: `kradzież`, ipa: `sa-ri-ka`},{ar: `ضائع`, pl: `zgubiony`, ipa: `da-i`},{ar: `هاتف`, pl: `telefon`, ipa: `ha-tif`},{ar: `اتصل`, pl: `dzwoń / zadzwoń`, ipa: `it-ta-sil`},{ar: `عنوان`, pl: `adres`, ipa: `un-wan`},{ar: `طوارئ`, pl: `nagły wypadek`, ipa: `ta-wa-ri`}], phrases: [{ar: `النجدة!`, pl: `Pomocy!`, ipa: `an-nadż-da`},{ar: `اتصل بالشرطة`, pl: `Zadzwoń na policję`, ipa: `it-ta-sil bisz-szur-ta`},{ar: `أحتاج إسعافًا`, pl: `Potrzebuję pogotowia`, ipa: `ah-tadż is-a-fan`},{ar: `أنا ضائع`, pl: `Zgubiłem się`, ipa: `a-na da-i`},{ar: `سُرقت حقيبتي`, pl: `Ukradziono moją torbę`, ipa: `su-ri-kat ha-ki-ba-ti`},{ar: `هذا عنواني`, pl: `To mój adres`, ipa: `ha-za un-wa-ni`}], grammar: `W nagłych sytuacjach najważniejsze są krótkie, jasne komunikaty. النجدة! jest mocnym wołaniem o pomoc. Jeśli nie znasz gramatyki, powiedz rzeczownik: شرطة, إسعاف, مساعدة, a rozmówca zwykle zrozumie kontekst.`, practice: [`Powiedz „Pomocy!”.`,`Poproś kogoś, by zadzwonił na policję.`,`Powiedz, że potrzebujesz pogotowia.`,`Powiedz, że zgubiłeś się.`,`Powiedz, że ukradziono twoją torbę.`]},{day: 21, title: `Pieniądze i płatności`, title_native: `المال والدفع`, focus: `Płacisz w sklepie w Doha i chcesz zapytać o kartę, gotówkę i rachunek. Uczysz się podstawowych zwrotów płatniczych.`, vocab: [{ar: `مال`, pl: `pieniądze`, ipa: `mal`},{ar: `نقدًا`, pl: `gotówką`, ipa: `nak-dan`},{ar: `بطاقة`, pl: `karta`, ipa: `bi-ta-ka`},{ar: `دفع`, pl: `płatność`, ipa: `daf`},{ar: `فاتورة`, pl: `rachunek`, ipa: `fa-tu-ra`},{ar: `إيصال`, pl: `paragon`, ipa: `i-sal`},{ar: `بنك`, pl: `bank`, ipa: `bank`},{ar: `صراف آلي`, pl: `bankomat`, ipa: `sar-raf a-li`},{ar: `عملة`, pl: `waluta`, ipa: `um-la`},{ar: `تغيير`, pl: `reszta`, ipa: `tagh-jir`}], phrases: [{ar: `هل أستطيع الدفع ببطاقة؟`, pl: `Czy mogę zapłacić kartą?`, ipa: `hal as-ta-ti ad-daf bi-bi-ta-ka`},{ar: `سأدفع نقدًا`, pl: `Zapłacę gotówką`, ipa: `sa-ad-fa nak-dan`},{ar: `أريد إيصالًا`, pl: `Chcę paragon`, ipa: `u-rid i-sa-lan`},{ar: `أين الصراف الآلي؟`, pl: `Gdzie jest bankomat?`, ipa: `aj-na as-sar-raf al-a-li`},{ar: `هل عندك تغيير؟`, pl: `Czy masz resztę?`, ipa: `hal in-dak tagh-jir`},{ar: `الفاتورة من فضلك`, pl: `Rachunek, proszę`, ipa: `al-fa-tu-ra min fad-lik`}], grammar: `بـ przyklejone do rzeczownika oznacza często „za pomocą”: ببطاقة znaczy „kartą”. نقدًا znaczy „gotówką” i może stać na końcu zdania. W sklepach i restauracjach pytanie o kartę jest bardzo praktyczne.`, practice: [`Zapytaj, czy można zapłacić kartą.`,`Powiedz, że zapłacisz gotówką.`,`Poproś o paragon.`,`Zapytaj, gdzie jest bankomat.`,`Poproś o rachunek.`]},{day: 22, title: `Telefon i internet`, title_native: `الهاتف والإنترنت`, focus: `Kupujesz kartę SIM w Dubaju i potrzebujesz internetu. Uczysz się pytać o Wi-Fi, hasło, numer telefonu i pakiet danych.`, vocab: [{ar: `هاتف`, pl: `telefon`, ipa: `ha-tif`},{ar: `إنترنت`, pl: `internet`, ipa: `in-tir-net`},{ar: `واي فاي`, pl: `Wi-Fi`, ipa: `waj faj`},{ar: `كلمة السر`, pl: `hasło`, ipa: `ka-li-mat as-sirr`},{ar: `رقم`, pl: `numer`, ipa: `ra-kam`},{ar: `شريحة`, pl: `karta SIM`, ipa: `sza-ri-ha`},{ar: `بيانات`, pl: `dane`, ipa: `ba-ja-nat`},{ar: `اتصال`, pl: `połączenie`, ipa: `it-ti-sal`},{ar: `بطارية`, pl: `bateria`, ipa: `bat-ta-ri-ja`},{ar: `شاحن`, pl: `ładowarka`, ipa: `sza-hin`}], phrases: [{ar: `هل عندكم واي فاي؟`, pl: `Czy macie Wi-Fi?`, ipa: `hal in-da-kum waj faj`},{ar: `ما كلمة السر؟`, pl: `Jakie jest hasło?`, ipa: `ma ka-li-mat as-sirr`},{ar: `أريد شريحة إنترنت`, pl: `Chcę kartę SIM z internetem`, ipa: `u-rid sza-ri-hat in-tir-net`},{ar: `كم سعر البيانات؟`, pl: `Ile kosztują dane?`, ipa: `kam si-r al-ba-ja-nat`},{ar: `أحتاج شاحنًا`, pl: `Potrzebuję ładowarki`, ipa: `ah-tadż sza-hi-nan`},{ar: `هذا رقمي`, pl: `To mój numer`, ipa: `ha-za ra-ka-mi`}], grammar: `كلمة السر dosłownie znaczy „słowo sekretu”, czyli hasło. عندكم jest bardzo użyteczne, gdy pytasz firmę lub lokal: هل عندكم واي فاي؟. W krajach arabskich przy zakupie karty SIM często może być potrzebny paszport.`, practice: [`Zapytaj, czy lokal ma Wi-Fi.`,`Zapytaj o hasło.`,`Powiedz, że chcesz kartę SIM z internetem.`,`Powiedz, że potrzebujesz ładowarki.`,`Podaj swój numer zdaniem هذا رقمي.`]},{day: 23, title: `Rozmowa towarzyska`, title_native: `الحديث الاجتماعي`, focus: `Rozmawiasz z lokalną osobą w kawiarni w Bejrucie. Uczysz się prostych tematów: kraj, praca, podróż i opinie.`, vocab: [{ar: `بلد`, pl: `kraj`, ipa: `ba-lad`},{ar: `مدينة`, pl: `miasto`, ipa: `ma-di-na`},{ar: `عمل`, pl: `praca`, ipa: `a-mal`},{ar: `دراسة`, pl: `nauka / studia`, ipa: `di-ra-sa`},{ar: `سفر`, pl: `podróż`, ipa: `sa-far`},{ar: `جميل`, pl: `piękny`, ipa: `dża-mil`},{ar: `ممتع`, pl: `interesujący / przyjemny`, ipa: `mum-ti`},{ar: `لطيف`, pl: `miły`, ipa: `la-tif`},{ar: `أحب`, pl: `lubię`, ipa: `u-hibb`},{ar: `أزور`, pl: `odwiedzam`, ipa: `a-zur`}], phrases: [{ar: `من أين أنت؟`, pl: `Skąd jesteś?`, ipa: `min aj-na an-ta`},{ar: `أنا من بولندا`, pl: `Jestem z Polski`, ipa: `a-na min bu-lan-da`},{ar: `هل تحب هذه المدينة؟`, pl: `Czy lubisz to miasto?`, ipa: `hal tu-hibb ha-zi-hi al-ma-di-na`},{ar: `أنا أحب السفر`, pl: `Lubię podróżować`, ipa: `a-na u-hibb as-sa-far`},{ar: `هذه المدينة جميلة`, pl: `To miasto jest piękne`, ipa: `ha-zi-hi al-ma-di-na dża-mi-la`},{ar: `تشرفت بلقائك`, pl: `Miło było cię poznać`, ipa: `ta-szar-raf-tu bi-li-ka-ik`}], grammar: `أحب oznacza „lubię/kocham” i łączy się z rzeczownikiem lub czynnością: أحب السفر. W arabskim przymiotnik dopasowuje się do rodzaju, więc مدينة جميلة ma formę żeńską جميلة. W praktyce najpierw zapamiętaj gotowe zdanie هذه المدينة جميلة.`, practice: [`Zapytaj kogoś, skąd jest.`,`Powiedz, że jesteś z Polski.`,`Powiedz, że lubisz podróżować.`,`Powiedz, że miasto jest piękne.`,`Zakończ rozmowę zdaniem تشرفت بلقائك.`]},{day: 24, title: `Zaproszenia i plany`, title_native: `الدعوات والخطط`, focus: `Poznajesz ludzi w hostelu w Maskacie i umawiacie się na spacer. Uczysz się mówić „chodźmy”, „może”, „dzisiaj wieczorem” i „nie mogę”.`, vocab: [{ar: `خطة`, pl: `plan`, ipa: `chut-ta`},{ar: `موعد`, pl: `spotkanie / termin`, ipa: `mau-id`},{ar: `اليوم`, pl: `dzisiaj`, ipa: `al-jaum`},{ar: `الليلة`, pl: `dziś wieczorem`, ipa: `al-laj-la`},{ar: `غدًا`, pl: `jutro`, ipa: `gha-dan`},{ar: `ربما`, pl: `może`, ipa: `rub-ba-ma`},{ar: `أستطيع`, pl: `mogę`, ipa: `as-ta-ti`},{ar: `لا أستطيع`, pl: `nie mogę`, ipa: `la as-ta-ti`},{ar: `نذهب`, pl: `idziemy`, ipa: `naz-hab`},{ar: `نلتقي`, pl: `spotykamy się`, ipa: `nal-ta-ki`}], phrases: [{ar: `هل نلتقي الليلة؟`, pl: `Czy spotkamy się dziś wieczorem?`, ipa: `hal nal-ta-ki al-laj-la`},{ar: `لنذهب إلى السوق`, pl: `Chodźmy na targ`, ipa: `lanaz-hab i-la as-suk`},{ar: `ربما غدًا`, pl: `Może jutro`, ipa: `rub-ba-ma gha-dan`},{ar: `لا أستطيع اليوم`, pl: `Nie mogę dzisiaj`, ipa: `la as-ta-ti al-jaum`},{ar: `في أي وقت؟`, pl: `O której godzinie?`, ipa: `fi ajj wakt`},{ar: `هذا مناسب لي`, pl: `To mi pasuje`, ipa: `ha-za mu-na-sib li`}], grammar: `لـ na początku czasownika może tworzyć propozycję: لنذهب znaczy „chodźmy/idźmy”. لا أستطيع to praktyczne „nie mogę”, a أستطيع znaczy „mogę”. W planach używaj prostych wyrażeń czasu: اليوم, الليلة, غدًا.`, practice: [`Zaproponuj spotkanie dziś wieczorem.`,`Powiedz „chodźmy na targ”.`,`Powiedz „może jutro”.`,`Powiedz, że nie możesz dzisiaj.`,`Zapytaj, o której godzinie.`]},{day: 25, title: `Na poczcie i wysyłka`, title_native: `في البريد والإرسال`, focus: `Wysyłasz kartkę lub paczkę z Marrakeszu do Polski. Uczysz się słów: poczta, znaczek, paczka, adres i wysłać.`, vocab: [{ar: `بريد`, pl: `poczta`, ipa: `ba-rid`},{ar: `طابع`, pl: `znaczek`, ipa: `ta-bi`},{ar: `بطاقة بريدية`, pl: `pocztówka`, ipa: `bi-ta-ka ba-ri-di-ja`},{ar: `رسالة`, pl: `list`, ipa: `ri-sa-la`},{ar: `طرد`, pl: `paczka`, ipa: `tard`},{ar: `عنوان`, pl: `adres`, ipa: `un-wan`},{ar: `إرسال`, pl: `wysyłka`, ipa: `ir-sal`},{ar: `إلى بولندا`, pl: `do Polski`, ipa: `i-la bu-lan-da`},{ar: `سريع`, pl: `szybki`, ipa: `sa-ri`},{ar: `بطيء`, pl: `wolny`, ipa: `ba-ti`}], phrases: [{ar: `أين مكتب البريد؟`, pl: `Gdzie jest poczta?`, ipa: `aj-na mak-tab al-ba-rid`},{ar: `أريد طابعًا`, pl: `Chcę znaczek`, ipa: `u-rid ta-bi-an`},{ar: `أريد إرسال هذا إلى بولندا`, pl: `Chcę wysłać to do Polski`, ipa: `u-rid ir-sal ha-za i-la bu-lan-da`},{ar: `كم يستغرق؟`, pl: `Ile to potrwa?`, ipa: `kam jas-tagh-rik`},{ar: `هل يوجد إرسال سريع؟`, pl: `Czy jest szybka wysyłka?`, ipa: `hal ju-dżad ir-sal sa-ri`},{ar: `هذا هو العنوان`, pl: `To jest adres`, ipa: `ha-za hu-wa al-un-wan`}], grammar: `إلى oznacza „do”, więc إلى بولندا znaczy „do Polski”. يوجد oznacza „istnieje / jest dostępne” i przydaje się w pytaniach o usługi: هل يوجد إرسال سريع؟. Przy wysyłce zapisuj adres wyraźnie alfabetem łacińskim i arabskim, jeśli trzeba.`, practice: [`Zapytaj, gdzie jest poczta.`,`Poproś o znaczek.`,`Powiedz, że chcesz wysłać coś do Polski.`,`Zapytaj, ile to potrwa.`,`Zapytaj o szybką wysyłkę.`]},{day: 26, title: `Wynajem i zakwaterowanie`, title_native: `الإيجار والسكن`, focus: `Szukasz apartamentu na kilka dni w Dubaju lub Ammanie. Uczysz się pytać o cenę za noc, klimatyzację, kuchnię i lokalizację.`, vocab: [{ar: `شقة`, pl: `apartament`, ipa: `szak-ka`},{ar: `إيجار`, pl: `wynajem`, ipa: `i-dżar`},{ar: `ليلة`, pl: `noc`, ipa: `laj-la`},{ar: `مطبخ`, pl: `kuchnia`, ipa: `mat-bach`},{ar: `مكيف`, pl: `klimatyzacja`, ipa: `mu-kaj-jif`},{ar: `إنترنت`, pl: `internet`, ipa: `in-tir-net`},{ar: `نظيف`, pl: `czysty`, ipa: `na-zif`},{ar: `هادئ`, pl: `cichy`, ipa: `ha-di`},{ar: `موقع`, pl: `lokalizacja`, ipa: `mau-ki`},{ar: `مفتاح`, pl: `klucz`, ipa: `mif-tah`}], phrases: [{ar: `كم السعر لليلة؟`, pl: `Ile kosztuje za noc?`, ipa: `kam as-si-r lil-laj-la`},{ar: `هل يوجد مكيف؟`, pl: `Czy jest klimatyzacja?`, ipa: `hal ju-dżad mu-kaj-jif`},{ar: `هل يوجد مطبخ؟`, pl: `Czy jest kuchnia?`, ipa: `hal ju-dżad mat-bach`},{ar: `الموقع جيد`, pl: `Lokalizacja jest dobra`, ipa: `al-mau-ki dżaj-jid`},{ar: `أحتاج المفتاح`, pl: `Potrzebuję klucza`, ipa: `ah-tadż al-mif-tah`},{ar: `الشقة نظيفة`, pl: `Apartament jest czysty`, ipa: `asz-szak-ka na-zi-fa`}], grammar: `لـ może oznaczać „dla” lub „za”, więc لليلة oznacza „za noc”. يوجد sprawdza się przy pytaniu, czy coś jest dostępne w mieszkaniu. Przymiotnik po rzeczowniku opisuje cechę: الشقة نظيفة.`, practice: [`Zapytaj o cenę za noc.`,`Zapytaj, czy jest klimatyzacja.`,`Zapytaj, czy jest kuchnia.`,`Powiedz, że lokalizacja jest dobra.`,`Powiedz, że apartament jest czysty.`]},{day: 27, title: `Pranie i codzienne usługi`, title_native: `الغسيل والخدمات اليومية`, focus: `Po kilku dniach podróży potrzebujesz pralni i drobnych usług. Uczysz się pytać o pranie, naprawę, godzinę odbioru i cenę.`, vocab: [{ar: `غسيل`, pl: `pranie`, ipa: `gha-sil`},{ar: `ملابس`, pl: `ubrania`, ipa: `ma-la-bis`},{ar: `نظيف`, pl: `czysty`, ipa: `na-zif`},{ar: `متسخ`, pl: `brudny`, ipa: `mut-ta-sich`},{ar: `مغسلة`, pl: `pralnia`, ipa: `magh-sa-la`},{ar: `إصلاح`, pl: `naprawa`, ipa: `is-lah`},{ar: `حذاء`, pl: `but`, ipa: `hi-za`},{ar: `ساعة`, pl: `godzina`, ipa: `sa-a`},{ar: `استلام`, pl: `odbiór`, ipa: `is-ti-lam`},{ar: `جاهز`, pl: `gotowy`, ipa: `dża-hiz`}], phrases: [{ar: `أين المغسلة؟`, pl: `Gdzie jest pralnia?`, ipa: `aj-na al-magh-sa-la`},{ar: `أريد غسل الملابس`, pl: `Chcę wyprać ubrania`, ipa: `u-rid ghasl al-ma-la-bis`},{ar: `متى يكون جاهزًا؟`, pl: `Kiedy będzie gotowe?`, ipa: `ma-ta ja-kun dża-hi-zan`},{ar: `كم السعر؟`, pl: `Ile kosztuje?`, ipa: `kam as-si-r`},{ar: `أحتاج إصلاح الحذاء`, pl: `Potrzebuję naprawy buta`, ipa: `ah-tadż is-lah al-hi-za`},{ar: `هل أستطيع الاستلام اليوم؟`, pl: `Czy mogę odebrać dzisiaj?`, ipa: `hal as-ta-ti al-is-ti-lam al-jaum`}], grammar: `أحتاج plus rzeczownik oznacza „potrzebuję czegoś”: أحتاج إصلاح, أحتاج دواء, أحتاج مساعدة. يكون oznacza „będzie/jest” w wielu kontekstach i pojawia się w pytaniu متى يكون جاهزًا؟. U usługodawców najważniejsze są cena i czas odbioru.`, practice: [`Zapytaj, gdzie jest pralnia.`,`Powiedz, że chcesz wyprać ubrania.`,`Zapytaj, kiedy będzie gotowe.`,`Zapytaj o cenę.`,`Zapytaj, czy możesz odebrać dzisiaj.`]},{day: 28, title: `Granice kultury i szacunek`, title_native: `الثقافة والاحترام`, focus: `Odwiedzasz miejsca religijne i lokalne dzielnice w krajach arabskich. Uczysz się pytać o zasady, ubiór, fotografowanie i zachowanie z szacunkiem.`, vocab: [{ar: `احترام`, pl: `szacunek`, ipa: `ih-ti-ram`},{ar: `ثقافة`, pl: `kultura`, ipa: `sa-ka-fa`},{ar: `قاعدة`, pl: `zasada`, ipa: `ka-i-da`},{ar: `لباس`, pl: `ubiór`, ipa: `li-bas`},{ar: `حذاء`, pl: `buty`, ipa: `hi-za`},{ar: `تصوير`, pl: `fotografowanie`, ipa: `tas-wir`},{ar: `مسموح`, pl: `dozwolone`, ipa: `mas-muh`},{ar: `ممنوع`, pl: `zakazane`, ipa: `mam-nu`},{ar: `هادئ`, pl: `cichy`, ipa: `ha-di`},{ar: `مناسب`, pl: `odpowiedni`, ipa: `mu-na-sib`}], phrases: [{ar: `هل هذا مسموح؟`, pl: `Czy to jest dozwolone?`, ipa: `hal ha-za mas-muh`},{ar: `هل التصوير ممنوع؟`, pl: `Czy fotografowanie jest zakazane?`, ipa: `hal at-tas-wir mam-nu`},{ar: `ما القاعدة هنا؟`, pl: `Jaka jest tutaj zasada?`, ipa: `ma al-ka-i-da hu-na`},{ar: `هل يجب خلع الحذاء؟`, pl: `Czy trzeba zdjąć buty?`, ipa: `hal ja-dżib chal al-hi-za`},{ar: `هل هذا اللباس مناسب؟`, pl: `Czy ten ubiór jest odpowiedni?`, ipa: `hal ha-za al-li-bas mu-na-sib`},{ar: `أريد أن أحترم المكان`, pl: `Chcę uszanować to miejsce`, ipa: `u-rid an ah-ta-rim al-ma-kan`}], grammar: `يجب oznacza „trzeba / należy” i jest przydatne przy zasadach: هل يجب...؟. Czasownik أريد أن... pozwala powiedzieć „chcę, żeby / chcę coś zrobić”, np. أريد أن أحترم. W kulturze podróży takie zdania brzmią uprzejmie i pokazują dobrą wolę.`, practice: [`Zapytaj, czy coś jest dozwolone.`,`Zapytaj, czy fotografowanie jest zakazane.`,`Zapytaj, czy trzeba zdjąć buty.`,`Zapytaj, czy ubiór jest odpowiedni.`,`Powiedz, że chcesz uszanować miejsce.`]},{day: 29, title: `Problemy i reklamacje`, title_native: `المشاكل والشكاوى`, focus: `W hotelu lub sklepie coś nie działa i musisz spokojnie wyjaśnić problem. Uczysz się mówić, że coś jest zepsute, nie działa lub jest inne niż zamówienie.`, vocab: [{ar: `مشكلة`, pl: `problem`, ipa: `musz-ki-la`},{ar: `مكسور`, pl: `zepsuty / złamany`, ipa: `mak-sur`},{ar: `لا يعمل`, pl: `nie działa`, ipa: `la ja-mal`},{ar: `خطأ`, pl: `błąd`, ipa: `cha-ta`},{ar: `غرفة`, pl: `pokój`, ipa: `ghur-fa`},{ar: `طلب`, pl: `zamówienie`, ipa: `ta-lab`},{ar: `مختلف`, pl: `inny`, ipa: `much-ta-lif`},{ar: `بارد`, pl: `zimny`, ipa: `ba-rid`},{ar: `ساخن`, pl: `gorący`, ipa: `sa-chin`},{ar: `مدير`, pl: `kierownik`, ipa: `mu-dir`}], phrases: [{ar: `عندي مشكلة`, pl: `Mam problem`, ipa: `in-di musz-ki-la`},{ar: `هذا لا يعمل`, pl: `To nie działa`, ipa: `ha-za la ja-mal`},{ar: `المكيف لا يعمل`, pl: `Klimatyzacja nie działa`, ipa: `al-mu-kaj-jif la ja-mal`},{ar: `هذا ليس طلبي`, pl: `To nie jest moje zamówienie`, ipa: `ha-za laj-sa ta-la-bi`},{ar: `أريد التحدث مع المدير`, pl: `Chcę porozmawiać z kierownikiem`, ipa: `u-rid at-ta-had-dus ma-a al-mu-dir`},{ar: `هل ممكن حل المشكلة؟`, pl: `Czy można rozwiązać problem?`, ipa: `hal mum-kin hall al-musz-ki-la`}], grammar: `لا يعمل to gotowa konstrukcja „nie działa”. ليس oznacza „nie jest” i pomaga korygować sytuację: هذا ليس طلبي. W reklamacji najlepiej zacząć od عندي مشكلة i mówić spokojnie, bez długich zdań.`, practice: [`Powiedz, że masz problem.`,`Powiedz, że klimatyzacja nie działa.`,`Powiedz, że to nie twoje zamówienie.`,`Poproś o rozmowę z kierownikiem.`,`Zapytaj, czy można rozwiązać problem.`]},{day: 30, title: `Ostatni dzień i pożegnanie`, title_native: `اليوم الأخير والوداع`, focus: `Kończysz podróż w kraju arabskojęzycznym i żegnasz się z ludźmi, którzy ci pomogli. Uczysz się dziękować, mówić o pięknym pobycie i planować powrót.`, vocab: [{ar: `وداع`, pl: `pożegnanie`, ipa: `wa-da`},{ar: `رحلة`, pl: `podróż`, ipa: `rih-la`},{ar: `إقامة`, pl: `pobyt`, ipa: `i-ka-ma`},{ar: `جميل`, pl: `piękny`, ipa: `dża-mil`},{ar: `رائع`, pl: `wspaniały`, ipa: `ra-i`},{ar: `سعيد`, pl: `szczęśliwy`, ipa: `sa-id`},{ar: `أعود`, pl: `wracam`, ipa: `a-ud`},{ar: `قريبًا`, pl: `wkrótce`, ipa: `ka-ri-ban`},{ar: `ذكريات`, pl: `wspomnienia`, ipa: `zik-ra-jat`},{ar: `شكرا لكم`, pl: `dziękuję wam`, ipa: `szuk-ran la-kum`}], phrases: [{ar: `كانت رحلة رائعة`, pl: `To była wspaniała podróż`, ipa: `ka-nat rih-la ra-i-a`},{ar: `شكرا على كل شيء`, pl: `Dziękuję za wszystko`, ipa: `szuk-ran a-la kul-li szaj`},{ar: `سأعود قريبًا`, pl: `Wrócę wkrótce`, ipa: `sa-a-ud ka-ri-ban`},{ar: `تشرفت بمعرفتك`, pl: `Miło było cię poznać`, ipa: `ta-szar-raf-tu bi-ma-ri-fa-tik`},{ar: `إلى اللقاء`, pl: `Do zobaczenia`, ipa: `i-la al-li-ka`},{ar: `أتمنى لك يومًا سعيدًا`, pl: `Życzę ci miłego dnia`, ipa: `a-ta-man-na lak jau-man sa-i-dan`}], grammar: `كانت oznacza „była” i pozwala opisać podróż w czasie przeszłym: كانت رحلة رائعة. سأعود to „wrócę”, gdzie سـ tworzy prostą przyszłość. Na koniec podróży bardzo naturalnie brzmi شكرا على كل شيء.`, practice: [`Powiedz: „Dziękuję za wszystko”.`,`Powiedz, że to była wspaniała podróż.`,`Powiedz, że wrócisz wkrótce.`,`Pożegnaj się słowami إلى اللقاء.`,`Napisz trzyzdaniowe pożegnanie po arabsku.`]}];

var CONVERSATIONS_PL_AR = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w kawiarni w Ammanie rano przed zwiedzaniem. Chcesz zamówić kawę, wodę i zapytać o rachunek.`, lines: [{who: `them`, ar: `صباح الخير، ماذا تريد؟`, pl: `Dzień dobry, co pan/pani chce?`},{who: `you`, ar: `صباح الخير، أريد قهوة من فضلك`, pl: `Dzień dobry, poproszę kawę.`},{who: `them`, ar: `هل تريد سكرًا؟`, pl: `Czy chce pan/pani cukier?`},{who: `you`, ar: `لا، بدون سكر من فضلك`, pl: `Nie, bez cukru, proszę.`},{who: `them`, ar: `هل تريد شيئًا آخر؟`, pl: `Czy chce pan/pani coś jeszcze?`},{who: `you`, ar: `نعم، ماء بارد من فضلك`, pl: `Tak, zimną wodę, proszę.`},{who: `them`, ar: `تفضل، القهوة والماء`, pl: `Proszę, kawa i woda.`},{who: `you`, ar: `شكرا، كم السعر؟`, pl: `Dziękuję, ile kosztuje?`},{who: `them`, ar: `خمسة دنانير`, pl: `Pięć dinarów.`},{who: `you`, ar: `تفضل، والفاتورة من فضلك`, pl: `Proszę, i rachunek poproszę.`},{who: `them`, ar: `تفضل، شكرا جزيلا`, pl: `Proszę, bardzo dziękuję.`},{who: `you`, ar: `شكرا، إلى اللقاء`, pl: `Dziękuję, do zobaczenia.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz do hotelu w Dubaju po długim locie. Masz rezerwację i pytasz o śniadanie oraz windę.`, lines: [{who: `them`, ar: `مرحبا، أهلا وسهلا`, pl: `Dzień dobry, witamy.`},{who: `you`, ar: `مرحبا، عندي حجز`, pl: `Dzień dobry, mam rezerwację.`},{who: `them`, ar: `ما اسمك من فضلك؟`, pl: `Jak się pan/pani nazywa?`},{who: `you`, ar: `اسمي آدم كوفالسكي`, pl: `Nazywam się Adam Kowalski.`},{who: `them`, ar: `هل عندك جواز السفر؟`, pl: `Czy ma pan/pani paszport?`},{who: `you`, ar: `نعم، تفضل`, pl: `Tak, proszę.`},{who: `them`, ar: `غرفتك في الطابق الخامس`, pl: `Pana/pani pokój jest na piątym piętrze.`},{who: `you`, ar: `شكرا، هل الإفطار مشمول؟`, pl: `Dziękuję, czy śniadanie jest wliczone?`},{who: `them`, ar: `نعم، الإفطار من السابعة إلى العاشرة`, pl: `Tak, śniadanie jest od siódmej do dziesiątej.`},{who: `you`, ar: `أين المصعد؟`, pl: `Gdzie jest winda?`},{who: `them`, ar: `المصعد هناك على اليمين`, pl: `Winda jest tam po prawej.`},{who: `you`, ar: `شكرا جزيلا`, pl: `Bardzo dziękuję.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Jesteś w medynie w Fezie i szukasz muzeum. Zatrzymujesz lokalną osobę i prosisz o proste wskazówki.`, lines: [{who: `you`, ar: `لو سمحت، أين المتحف؟`, pl: `Przepraszam, gdzie jest muzeum?`},{who: `them`, ar: `المتحف قريب من هنا`, pl: `Muzeum jest blisko stąd.`},{who: `you`, ar: `هل أذهب مستقيمًا؟`, pl: `Czy mam iść prosto?`},{who: `them`, ar: `نعم، اذهب مستقيمًا`, pl: `Tak, idź prosto.`},{who: `you`, ar: `ثم إلى اليمين أو اليسار؟`, pl: `Potem w prawo czy w lewo?`},{who: `them`, ar: `إلى اليسار عند السوق`, pl: `W lewo przy targu.`},{who: `you`, ar: `هل هو بعيد؟`, pl: `Czy to daleko?`},{who: `them`, ar: `لا، خمس دقائق فقط`, pl: `Nie, tylko pięć minut.`},{who: `you`, ar: `شكرا جزيلا`, pl: `Bardzo dziękuję.`},{who: `them`, ar: `عفوا، أهلا وسهلا`, pl: `Nie ma za co, proszę bardzo.`},{who: `you`, ar: `يوم سعيد`, pl: `Miłego dnia.`},{who: `them`, ar: `ولك أيضا`, pl: `Nawzajem.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Jesteś w restauracji w Bejrucie i chcesz zjeść coś lokalnego. Pytasz o menu, rekomendację i danie bez mięsa.`, lines: [{who: `them`, ar: `مساء الخير، تفضل`, pl: `Dobry wieczór, zapraszam.`},{who: `you`, ar: `مساء الخير، أريد قائمة الطعام من فضلك`, pl: `Dobry wieczór, poproszę menu.`},{who: `them`, ar: `تفضل، ماذا تريد أن تأكل؟`, pl: `Proszę, co chce pan/pani zjeść?`},{who: `you`, ar: `ماذا تنصح؟`, pl: `Co pan/pani poleca?`},{who: `them`, ar: `الدجاج مع الأرز لذيذ جدا`, pl: `Kurczak z ryżem jest bardzo smaczny.`},{who: `you`, ar: `هل عندكم طعام نباتي؟`, pl: `Czy macie jedzenie wegetariańskie?`},{who: `them`, ar: `نعم، عندنا سلطة وخبز وأرز`, pl: `Tak, mamy sałatkę, chleb i ryż.`},{who: `you`, ar: `أريد طعامًا نباتيًا بدون لحم`, pl: `Chcę danie wegetariańskie bez mięsa.`},{who: `them`, ar: `هل تريد ماء أو شاي؟`, pl: `Czy chce pan/pani wodę czy herbatę?`},{who: `you`, ar: `ماء بارد من فضلك`, pl: `Zimną wodę, proszę.`},{who: `them`, ar: `حاضر، لحظة من فضلك`, pl: `Oczywiście, chwileczkę proszę.`},{who: `you`, ar: `شكرا`, pl: `Dziękuję.`}]},{id: 5, title: `Kupowanie biletu na metro`, scene: `Jesteś przy automacie lub okienku metra w Kairze. Chcesz kupić bilet i upewnić się, że jedziesz w dobrym kierunku.`, lines: [{who: `them`, ar: `مرحبا، إلى أين؟`, pl: `Dzień dobry, dokąd?`},{who: `you`, ar: `أريد تذكرة إلى المتحف`, pl: `Chcę bilet do muzeum.`},{who: `them`, ar: `تذكرة واحدة؟`, pl: `Jeden bilet?`},{who: `you`, ar: `نعم، تذكرة واحدة من فضلك`, pl: `Tak, jeden bilet poproszę.`},{who: `them`, ar: `السعر عشرة جنيهات`, pl: `Cena to dziesięć funtów.`},{who: `you`, ar: `تفضل`, pl: `Proszę.`},{who: `them`, ar: `هذا هو الخط الثاني`, pl: `To jest druga linia.`},{who: `you`, ar: `هل هذه المحطة قريبة من المتحف؟`, pl: `Czy ta stacja jest blisko muzeum?`},{who: `them`, ar: `نعم، قريبة جدا`, pl: `Tak, bardzo blisko.`},{who: `you`, ar: `إلى أي اتجاه أذهب؟`, pl: `W którym kierunku mam iść?`},{who: `them`, ar: `إلى اليمين ثم مستقيمًا`, pl: `W prawo, potem prosto.`},{who: `you`, ar: `شكرا جزيلا`, pl: `Bardzo dziękuję.`}]},{id: 6, title: `Zakupy na targu`, scene: `Jesteś na targu w Marrakeszu i oglądasz szalik. Chcesz zapytać o cenę, kolor i trochę negocjować.`, lines: [{who: `them`, ar: `مرحبا، تفضل، هذا جميل`, pl: `Dzień dobry, proszę, to jest piękne.`},{who: `you`, ar: `مرحبا، كم السعر؟`, pl: `Dzień dobry, ile kosztuje?`},{who: `them`, ar: `مئة درهم`, pl: `Sto dirhamów.`},{who: `you`, ar: `هذا غالي قليلا`, pl: `To trochę drogie.`},{who: `them`, ar: `هذا جيد وجديد`, pl: `To jest dobre i nowe.`},{who: `you`, ar: `هل عندك لون أزرق؟`, pl: `Czy ma pan/pani kolor niebieski?`},{who: `them`, ar: `نعم، عندي أزرق وأسود`, pl: `Tak, mam niebieski i czarny.`},{who: `you`, ar: `أريد الأزرق، لكن بسعر أقل`, pl: `Chcę niebieski, ale za niższą cenę.`},{who: `them`, ar: `تسعون درهمًا`, pl: `Dziewięćdziesiąt dirhamów.`},{who: `you`, ar: `حسنا، سآخذه`, pl: `Dobrze, wezmę.`},{who: `them`, ar: `شكرا، تفضل`, pl: `Dziękuję, proszę.`},{who: `you`, ar: `شكرا لك`, pl: `Dziękuję panu/pani.`}]},{id: 7, title: `W aptece`, scene: `Jesteś w Casablance i boli cię głowa. Wchodzisz do apteki, prosisz o lekarstwo i pytasz, czy potrzebujesz lekarza.`, lines: [{who: `them`, ar: `مرحبا، كيف أساعدك؟`, pl: `Dzień dobry, jak mogę pomóc?`},{who: `you`, ar: `مرحبا، عندي ألم في الرأس`, pl: `Dzień dobry, boli mnie głowa.`},{who: `them`, ar: `هل عندك حمى؟`, pl: `Czy ma pan/pani gorączkę?`},{who: `you`, ar: `لا، لا حمى`, pl: `Nie, nie mam gorączki.`},{who: `them`, ar: `هل عندك حساسية؟`, pl: `Czy ma pan/pani alergię?`},{who: `you`, ar: `لا، ليس عندي حساسية`, pl: `Nie, nie mam alergii.`},{who: `them`, ar: `هذا دواء للصداع`, pl: `To lekarstwo na ból głowy.`},{who: `you`, ar: `كم مرة في اليوم؟`, pl: `Ile razy dziennie?`},{who: `them`, ar: `مرتين في اليوم بعد الطعام`, pl: `Dwa razy dziennie po jedzeniu.`},{who: `you`, ar: `هل أحتاج طبيبًا؟`, pl: `Czy potrzebuję lekarza?`},{who: `them`, ar: `إذا استمر الألم، نعم`, pl: `Jeśli ból się utrzyma, tak.`},{who: `you`, ar: `شكرا جزيلا`, pl: `Bardzo dziękuję.`}]},{id: 8, title: `Rozmowa z lokalną osobą`, scene: `Siedzisz w kawiarni w Tunisie i zaczynasz spokojną rozmowę z osobą przy sąsiednim stoliku. Chcesz powiedzieć, skąd jesteś, że podoba ci się miasto i że lubisz podróżować.`, lines: [{who: `you`, ar: `مرحبا، هل هذا المكان فارغ؟`, pl: `Dzień dobry, czy to miejsce jest wolne?`},{who: `them`, ar: `نعم، تفضل`, pl: `Tak, proszę.`},{who: `you`, ar: `شكرا، أنا من بولندا`, pl: `Dziękuję, jestem z Polski.`},{who: `them`, ar: `أهلا وسهلا، هل هذه أول مرة هنا؟`, pl: `Witamy, czy to pierwszy raz tutaj?`},{who: `you`, ar: `نعم، أول مرة في تونس`, pl: `Tak, pierwszy raz w Tunezji.`},{who: `them`, ar: `هل تحب المدينة؟`, pl: `Czy podoba ci się miasto?`},{who: `you`, ar: `نعم، المدينة جميلة والناس لطفاء`, pl: `Tak, miasto jest piękne, a ludzie mili.`},{who: `them`, ar: `ماذا تحب أن تزور؟`, pl: `Co lubisz zwiedzać?`},{who: `you`, ar: `أحب المتاحف والأسواق القديمة`, pl: `Lubię muzea i stare targi.`},{who: `them`, ar: `السوق قريب من هنا`, pl: `Targ jest blisko stąd.`},{who: `you`, ar: `رائع، شكرا على النصيحة`, pl: `Wspaniale, dziękuję za radę.`},{who: `them`, ar: `عفوا، رحلة سعيدة`, pl: `Nie ma za co, miłej podróży.`}]}];